#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B, C, D;
        scanf("%d %d %d %d", &A, &B, &C, &D);
        if (A + C == 180 && B + D == 180) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

