import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); C = int(next(it)); D = int(next(it))
        if A + C == 180 and B + D == 180:
            out_lines.append("YES")
        else:
            out_lines.append("NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

